// Parse usage data and check thresholds
const raw = $input.first().json.stdout || '{}';
let usage;
try {
  usage = JSON.parse(raw);
} catch {
  usage = { date: new Date().toISOString().slice(0, 10), claude_requests: 0, gemini_requests: 0 };
}

// Daily limits (configurable via env)
const CLAUDE_DAILY_LIMIT = parseInt($env.CLAUDE_DAILY_LIMIT || '1000');
const GEMINI_DAILY_LIMIT = parseInt($env.GEMINI_DAILY_LIMIT || '500');

const claude_pct = (usage.claude_requests / CLAUDE_DAILY_LIMIT) * 100;
const gemini_pct = (usage.gemini_requests / GEMINI_DAILY_LIMIT) * 100;

const alerts = [];
if (claude_pct > 80) alerts.push(`Claude: ${usage.claude_requests}/${CLAUDE_DAILY_LIMIT} (${claude_pct.toFixed(0)}%)`);
if (gemini_pct > 80) alerts.push(`Gemini: ${usage.gemini_requests}/${GEMINI_DAILY_LIMIT} (${gemini_pct.toFixed(0)}%)`);

return [{
  json: {
    ...usage,
    claude_pct: claude_pct.toFixed(1),
    gemini_pct: gemini_pct.toFixed(1),
    has_warning: alerts.length > 0,
    warning_message: alerts.length > 0 ? `⚠️ Token Usage Warning:\n${alerts.join('\n')}` : ''
  }
}];
